        },
        "isCoordinates": {
          "type": "boolean",
          "default": false,
          "description": "Whether the value is coordinates"
        }
      },
      "required": [
        "value"
      ],
      "additionalProperties": false,
      "description": "Search center point"
    },
    "keyword": {
      "type": "string",
      "description": "Search keyword (e.g., restaurant, cafe, hotel)"
    },
    "radius": {
      "type": "number",
      "default": 1000,
      "description": "Search radius in meters"
    },
